#include "snd_p_snd.h"

// Do not edit this file as it will be overwritten if HAMR codegen is rerun

void snd_p_snd_initialize(void);
void snd_p_snd_notify(microkit_channel channel);
void snd_p_snd_timeTriggered(void);

volatile sb_queue_int32_t_1_t *out_val_queue_1;
volatile sb_queue_uint8_t_1_t *evt_queue_1;

#define PORT_FROM_MON 0

bool put_out_val(const int32_t *data) {
  sb_queue_int32_t_1_enqueue((sb_queue_int32_t_1_t *) out_val_queue_1, (int32_t *) data);

  return true;
}

bool put_evt() {
  uint8_t eventPayload = 0; // always send 0 as the event payload
  uint8_t *data = &eventPayload;
  sb_queue_uint8_t_1_enqueue((sb_queue_uint8_t_1_t *) evt_queue_1, (uint8_t *) data);

  return true;
}

void init(void) {
  printf("%s | INIT!\n", microkit_name);

  sb_queue_int32_t_1_init((sb_queue_int32_t_1_t *) out_val_queue_1);

  sb_queue_uint8_t_1_init((sb_queue_uint8_t_1_t *) evt_queue_1);

  snd_p_snd_initialize();

  microkit_notify(PORT_FROM_MON);
}

void notified(microkit_channel channel) {
  switch (channel) {
    case PORT_FROM_MON:
      snd_p_snd_timeTriggered();
      break;
    default:
      snd_p_snd_notify(channel);
  }
}
